  "经历是「负责 X」式职责罗列"
  "要定渠道策略（networking vs 网申）"
  "做信息面谈 / networking 触达"
  "区分简历 / 面试准备的「优化」与「造假」"
)
declare -a RULE_ACTIONS=(
  "组织原点必须是「这个岗位 / 招聘方在解决什么问题」，不是「我有什么 / 我想说什么」—— JD 先拆成「硬性要求 / 加分项 / 高频关键词 / 真正在解决的问题」"
  "套 X-Y-Z（做到了 X，X 用 Y 衡量，靠做 Z）/ STAR 重构，每段经历必须有可衡量的 Result —— 用数字 / 结果，不用职责描述"
  "按赛道判断不站队 —— 海外科技 / 咨询 / 中高层级 / 转行场景 networking 权重高；国内校招「网申 + 笔试」仍是主通道；大批量流程化招聘的初级岗 networking 边际收益低。先判断赛道，再配工具"
  "守「第一次不要工作」铁律 —— 先了解、先建立关系、先给价值，不一开口就要工作 / 要内推"
  "硬划红线 —— 量化真实成就 / ATS 关键词 / 措辞提升 / 用目标岗位语言重新包装真实技能 = 合法优化；编造经历 / 改头衔 / 虚构数字 / 背题库假装有不具备的能力 = 造假，背调和试用期会暴露"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
